"use strict";parserFactory.register("indowebnovel.id",()=>new IndowebnovelParser);class IndowebnovelParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("div.lightnovel-episode");return util.hyperlinksToChapterList(t).map(this.adjustChapterTitle).reverse()}adjustChapterTitle(e){let t=e.title.replace(/\r\n|\r|\n|Bahasa Indonesia/g,""),r=t.indexOf("Chapter");return 0<r&&(t=t.substring(r)),e.title=t.trim(),e}findContent(e){return[...e.querySelectorAll("div")].filter(e=>"123"===e.className)[0]}extractTitleImpl(e){return e.querySelector("h1.entry-title")}findChapterTitle(e){return e.querySelector("h1.entry-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.lightnovel-thumb")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".lightnovel-info, .lightnovel-synopsis")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"script")}}